        visited = [[False]*w for _ in range(h)]
        objects = []
        for r in range(h):
            for c in range(w):
                if int(g[r, c]) != bg_val and not visited[r][c]:
                    q = deque([(r, c)])
                    visited[r][c] = True
                    cells = [(r, c)]
                    while q:
                        cr, cc2 = q.popleft()
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                            nr, nc = cr+dr, cc2+dc
                            if 0<=nr<h and 0<=nc<w and not visited[nr][nc] and int(g[nr, nc]) != bg_val:
