                                q.append((nr, nc))
                                cells.append((nr, nc))
                    rows = [c[0] for c in cells]
                    cols = [c[1] for c in cells]
                    bbox = (min(rows), min(cols), max(rows), max(cols))
                    objects.append({'cells': cells, 'bbox': bbox})
        return objects

